 1	import React, { FC } from 'react';
 2	
 3	import { V1alpha1VirtualMachineClone } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import {
 6	  Alert,
 7	  AlertVariant,
 8	  ProgressStep,
 9	  ProgressStepper,
10	  ProgressStepVariant,
11	  Stack,
12	} from '@patternfly/react-core';
13	
14	import { CLONING_STATUSES, STATUS_TO_PROGRESS_VARIANT } from '../utils/constants';
15	
16	type CloningStatusProps = {
17	  vmCloneRequest: V1alpha1VirtualMachineClone;
18	};
19	
20	const CloningStatus: FC<CloningStatusProps> = ({ vmCloneRequest }) => {
21	  const { t } = useKubevirtTranslation();
22	
23	  const phase = vmCloneRequest?.status?.phase;
24	
25	  const progressStatus = STATUS_TO_PROGRESS_VARIANT[phase];
26	
27	  const isFailed = [CLONING_STATUSES.FAILED, CLONING_STATUSES.UNKNOWN].includes(
28	    phase as CLONING_STATUSES,
29	  );
30	
31	  if (!Boolean(vmCloneRequest)) return null;
32	
33	  return (
34	    <Stack hasGutter>
35	      <ProgressStepper aria-label="VirtualMachine cloning steps" isCenterAligned>
36	        <ProgressStep
37	          aria-label={t('Request sent')}
38	          id="basic-step1"
39	          titleId="Request sent"
40	          variant={ProgressStepVariant.success}
41	        >
42	          {t('Request sent')}
43	        </ProgressStep>
44	        <ProgressStep
45	          aria-label={isFailed ? t('Failed') : t('In process')}
46	          id="basic-step2"
47	          isCurrent
48	          titleId="In process"
49	          variant={progressStatus}
50	        >
51	          {isFailed ? t('Failed') : t('In process')}
52	        </ProgressStep>
53	        <ProgressStep
54	          variant={
55	            phase === CLONING_STATUSES.SUCCEEDED
56	              ? ProgressStepVariant.success
57	              : ProgressStepVariant.pending
58	          }
59	          aria-label={t('Created')}
60	          id="basic-step3"
61	          titleId="Created"
62	        >
63	          {t('Created')}
64	        </ProgressStep>
65	      </ProgressStepper>
66	
67	      {phase === CLONING_STATUSES.FAILED && (
68	        <Alert
69	          isInline
70	          title={t('An error occurred during the cloning process')}
71	          variant={AlertVariant.danger}
72	        >
73	          {vmCloneRequest?.status?.conditions?.find((c) => c.status === 'True')?.message ||
74	            'unknown'}
75	        </Alert>
76	      )}
77	    </Stack>
78	  );
79	};
80	
81	export default CloningStatus;

